class Solution:
    def longestEqualSubarray(self, nums, k):
        n = len(nums)
        best = 0
        for i in range(n):
            freq = {}
            maxf = 0
            for j in range(i, n):
                freq[nums[j]] = freq.get(nums[j], 0) + 1
                if freq[nums[j]] > maxf:
                    maxf = freq[nums[j]]
                length = j - i + 1
                if length - maxf <= k and maxf > best:
                    best = maxf
        return best

