class Solution:
    def longestEqualSubarray(self, nums, k):
        count = {}
        left = 0
        best = 0
        for right in range(len(nums)):
            v = nums[right]
            count[v] = count.get(v, 0) + 1
            if count[v] > best:
                best = count[v]
            window_len = right - left + 1
            if window_len - best > k:
                lv = nums[left]
                count[lv] -= 1
                left += 1
        return best

