var longestEqualSubarray = function(nums, k) {
    const count = new Map();
    let left = 0;
    let best = 0;
    for (let right = 0; right < nums.length; right++) {
        const v = nums[right];
        count.set(v, (count.get(v) || 0) + 1);
        if (count.get(v) > best) best = count.get(v);
        const windowLen = right - left + 1;
        if (windowLen - best > k) {
            const lv = nums[left];
            count.set(lv, count.get(lv) - 1);
            left += 1;
        }
    }
    return best;
};
